head.b:skin:
/* * MODERN PLAYER THEME - MOBILE FIXED
 */

:root {
    --primary-color: #6366f1;
    --primary-hover: #4f46e5;
    --accent-color: #ec4899;
    --bg-dark: #0f172a;
    --glass-bg: rgba(30, 41, 59, 0.7);
    --glass-border: rgba(255, 255, 255, 0.1);
    --text-main: #f8fafc;
    --text-muted: #94a3b8;
}

body { 
    margin: 0; padding: 0;
    background: radial-gradient(circle at top left, #1e1b4b, #0f172a);
    color: var(--text-main); 
    font-family: 'Inter', sans-serif; 
    height: 100vh;
    height: 100dvh; 
    overflow: hidden;
    -webkit-font-smoothing: antialiased;
}

/* --- LOADING EKRANI --- */
#loading-screen {
    position: fixed;
    top: 0; left: 0;
    width: 100%; height: 100%;
    background: #0f172a;
    z-index: 999999;
    display: flex;
    justify-content: center;
    align-items: center;
    transition: all 0.6s cubic-bezier(0.4, 0, 0.2, 1);
}

.loader {
    width: 60px;
    height: 60px;
    border: 4px solid rgba(99, 102, 241, 0.1);
    border-left-color: var(--primary-color);
    border-radius: 50%;
    animation: spin 1s cubic-bezier(0.55, 0.055, 0.675, 0.19) infinite;
    box-shadow: 0 0 20px rgba(99, 102, 241, 0.3);
}

@keyframes spin { 100% { transform: rotate(360deg); } }

/* --- GİRİŞ EKRANI --- */
#generator-screen {
    display: flex; flex-direction: column;
    justify-content: center; align-items: center;
    height: 100%; width: 100%;
    position: relative;
    z-index: 20;
    overflow-y: auto; 
}

.card {
    background: var(--glass-bg);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    padding: 40px;
    border-radius: 24px;
    border: 1px solid var(--glass-border);
    box-shadow: 0 25px 50px -12px rgba(0, 0, 0, 0.5);
    text-align: center;
    width: 90%; max-width: 480px;
    transition: transform 0.3s ease;
}

.card:hover { transform: translateY(-5px); }

h2 { 
    margin: 0 0 30px 0; 
    color: #fff; 
    font-size: 24px; 
    font-weight: 700;
    letter-spacing: -0.5px;
    display: flex; align-items: center; justify-content: center; gap: 10px;
}

h2 i { color: var(--primary-color); text-shadow: 0 0 15px rgba(99,102,241,0.5); }

.input-group { margin-bottom: 20px; text-align: left; }

/* YAN YANA INPUT GRUBU İÇİN YENİ CSS */
.double-group {
    display: flex;
    gap: 15px;
}
.double-group > div {
    flex: 1;
}

.input-group label { 
    display: block; font-size: 12px; 
    color: var(--text-muted); 
    margin-bottom: 8px; 
    font-weight: 600; 
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

input[type="text"] {
    width: 100%; padding: 16px;
    background: rgba(0, 0, 0, 0.2); 
    border: 1px solid var(--glass-border);
    color: #fff; 
    border-radius: 12px; 
    box-sizing: border-box;
    font-family: 'Inter', sans-serif;
    font-size: 14px;
    transition: all 0.3s ease;
}

input[type="text"]:focus {
    outline: none;
    border-color: var(--primary-color);
    box-shadow: 0 0 0 4px rgba(99, 102, 241, 0.15);
    background: rgba(0, 0, 0, 0.4);
}

button.generate-btn {
    background: linear-gradient(135deg, var(--primary-color), var(--primary-hover));
    color: white;
    border: none; padding: 18px; border-radius: 12px;
    cursor: pointer; font-weight: 700; width: 100%; margin-top: 10px;
    font-size: 16px; 
    letter-spacing: 0.5px;
    box-shadow: 0 10px 20px -10px rgba(99, 102, 241, 0.5);
    transition: all 0.3s ease;
}

button.generate-btn:hover { 
    transform: translateY(-2px); 
    box-shadow: 0 15px 25px -10px rgba(99, 102, 241, 0.6);
}

.result-box {
    margin-top: 25px; padding: 20px;
    background: rgba(0,0,0,0.3); 
    border: 1px dashed rgba(255,255,255,0.2);
    word-break: break-all; display: none; 
    border-radius: 12px;
    text-align: left;
}
.result-box p { font-size: 12px; font-weight: 600; margin-bottom: 8px; color: var(--text-muted); }
.result-box a { 
    color: var(--accent-color); 
    text-decoration: none; 
    font-size: 13px; 
    font-family: monospace;
    line-height: 1.4;
}

/* --- PLAYER EKRANI --- */
#player-wrapper {
    position: absolute; top: 0; left: 0; 
    width: 100%; 
    height: 100%;
    height: 100dvh; 
    z-index: 50; background: #000; display: none;
}

.plyr { width: 100%; height: 100%; font-family: 'Inter', sans-serif; }

/* Mobil Fullscreen Fix */
.plyr--fullscreen-enabled [data-plyr=fullscreen] { display: block !important; }

.plyr--full-ui input[type=range] { color: var(--primary-color); }
.plyr__control--overlaid { background: rgba(99, 102, 241, 0.9); }

/* Modern Dil Değiştirme Paneli */
#lang-switcher {
    position: absolute; top: 25px; right: 25px;
    z-index: 9999; 
    background: rgba(15, 23, 42, 0.6); 
    padding: 6px; 
    border-radius: 50px; 
    display: flex; gap: 4px;
    backdrop-filter: blur(10px);
    display: none; 
    border: 1px solid rgba(255,255,255,0.08);
    box-shadow: 0 10px 25px rgba(0,0,0,0.3);
}

.lang-btn {
    background: transparent; 
    border: none;
    color: var(--text-muted); 
    padding: 10px 18px;
    cursor: pointer; 
    font-size: 13px; 
    border-radius: 40px;
    font-weight: 600; 
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    display: flex; align-items: center; gap: 8px;
}

.lang-btn i { font-size: 14px; }
.lang-btn.active {
    background: var(--primary-color); 
    color: #fff; 
    box-shadow: 0 4px 15px rgba(99, 102, 241, 0.4);
}

@media (max-width: 500px) {
    #lang-switcher { top: 15px; right: 15px; padding: 4px; }
    .lang-btn { padding: 8px 12px; font-size: 12px; }
    .card { padding: 25px; width: 85%; margin-top: 20px; margin-bottom: 20px;}
    .double-group { flex-direction: column; gap: 10px; } /* Mobilde alt alta olsun */
}

.section, .widget { display: none !important; }

b:includable.script:
    (function() {
      var items = ;
      var msgs = ;
      var config = ;

// 
      var cursor = null;
      if (items && items.length > 0) {
        cursor = parseInt(items[items.length - 1].timestamp) + 1;
      }

      var bodyFromEntry = function(entry) {
        var text = (entry &&
                    ((entry.content && entry.content.$t) ||
                     (entry.summary && entry.summary.$t))) ||
            '';
        if (entry && entry.gd$extendedProperty) {
          for (var k in entry.gd$extendedProperty) {
            if (entry.gd$extendedProperty[k].name == 'blogger.contentRemoved') {
              return '<span class="deleted-comment">' + text + '</span>';
            }
          }
        }
        return text;
      }

      var parse = function(data) {
        cursor = null;
        var comments = [];
        if (data && data.feed && data.feed.entry) {
          for (var i = 0, entry; entry = data.feed.entry[i]; i++) {
            var comment = {};
            // comment ID, parsed out of the original id format
            var id = /blog-(\d+).post-(\d+)/.exec(entry.id.$t);
            comment.id = id ? id[2] : null;
            comment.body = bodyFromEntry(entry);
            comment.timestamp = Date.parse(entry.published.$t) + '';
            if (entry.author && entry.author.constructor === Array) {
              var auth = entry.author[0];
              if (auth) {
                comment.author = {
                  name: (auth.name ? auth.name.$t : undefined),
                  profileUrl: (auth.uri ? auth.uri.$t : undefined),
                  avatarUrl: (auth.gd$image ? auth.gd$image.src : undefined)
                };
              }
            }
            if (entry.link) {
              if (entry.link[2]) {
                comment.link = comment.permalink = entry.link[2].href;
              }
              if (entry.link[3]) {
                var pid = /.*comments\/default\/(\d+)\?.*/.exec(entry.link[3].href);
                if (pid && pid[1]) {
                  comment.parentId = pid[1];
                }
              }
            }
            comment.deleteclass = 'item-control blog-admin';
            if (entry.gd$extendedProperty) {
              for (var k in entry.gd$extendedProperty) {
                if (entry.gd$extendedProperty[k].name == 'blogger.itemClass') {
                  comment.deleteclass += ' ' + entry.gd$extendedProperty[k].value;
                } else if (entry.gd$extendedProperty[k].name == 'blogger.displayTime') {
                  comment.displayTime = entry.gd$extendedProperty[k].value;
                }
              }
            }
            comments.push(comment);
          }
        }
        return comments;
      };

      var paginator = function(callback) {
        if (hasMore()) {
          var url = config.feed + '?alt=json&v=2&orderby=published&reverse=false&max-results=50';
          if (cursor) {
            url += '&published-min=' + new Date(cursor).toISOString();
          }
          window.bloggercomments = function(data) {
            var parsed = parse(data);
            cursor = parsed.length < 50 ? null
                : parseInt(parsed[parsed.length - 1].timestamp) + 1
            callback(parsed);
            window.bloggercomments = null;
          }
          url += '&callback=bloggercomments';
          var script = document.createElement('script');
          script.type = 'text/javascript';
          script.src = url;
          document.getElementsByTagName('head')[0].appendChild(script);
        }
      };
      var hasMore = function() {
        return !!cursor;
      };
      var getMeta = function(key, comment) {
        if ('iswriter' == key) {
          var matches = !!comment.author
              && comment.author.name == config.authorName
              && comment.author.profileUrl == config.authorUrl;
          return matches ? 'true' : '';
        } else if ('deletelink' == key) {
          return config.baseUri + '/comment/delete/'
               + config.blogId + '/' + comment.id;
        } else if ('deleteclass' == key) {
          return comment.deleteclass;
        }
        return '';
      };

      var replybox = null;
      var replyUrlParts = null;
      var replyParent = undefined;

      var onReply = function(commentId, domId) {
        if (replybox == null) {
          // lazily cache replybox, and adjust to suit this style:
          replybox = document.getElementById('comment-editor');
          if (replybox != null) {
            replybox.height = '250px';
            replybox.style.display = 'block';
            replyUrlParts = replybox.src.split('#');
          }
        }
        if (replybox && (commentId !== replyParent)) {
          replybox.src = '';
          document.getElementById(domId).insertBefore(replybox, null);
          replybox.src = replyUrlParts[0]
              + (commentId ? '&parentID=' + commentId : '')
              + '#' + replyUrlParts[1];
          replyParent = commentId;
        }
      };

      var hash = (window.location.hash || '#').substring(1);
      var startThread, targetComment;
      if (/^comment-form_/.test(hash)) {
        startThread = hash.substring('comment-form_'.length);
      } else if (/^c[0-9]+$/.test(hash)) {
        targetComment = hash.substring(1);
      }

      // Configure commenting API:
      var configJso = {
        'maxDepth': config.maxThreadDepth
      };
      var provider = {
        'id': config.postId,
        'data': items,
        'loadNext': paginator,
        'hasMore': hasMore,
        'getMeta': getMeta,
        'onReply': onReply,
        'rendered': true,
        'initComment': targetComment,
        'initReplyThread': startThread,
        'config': configJso,
        'messages': msgs
      };

      var render = function() {
        if (window.goog && window.goog.comments) {
          var holder = document.getElementById('comment-holder');
          window.goog.comments.render(holder, provider);
        }
      };

      // render now, or queue to render when library loads:
      if (window.goog && window.goog.comments) {
        render();
      } else {
        window.goog = window.goog || {};
        window.goog.comments = window.goog.comments || {};
        window.goog.comments.loadQueue = window.goog.comments.loadQueue || [];
        window.goog.comments.loadQueue.push(render);
      }
    })();
//

body.script:
//
let player;
let linkEn = "";
let linkTr = "";
let linkSub = "";
let nameEn = "";
let nameTr = "";
let currentLang = "en";

window.onload = function() {
    // Loading gizle
    setTimeout(function() {
        var loader = document.getElementById('loading-screen');
        if(loader) {
            loader.style.opacity = '0';
            loader.style.visibility = 'hidden';
        }
    }, 3000); 

    const urlParams = new URLSearchParams(window.location.search);
    linkEn = urlParams.get('v');
    linkTr = urlParams.get('d');
    linkSub = urlParams.get('s');

    // Buton İsimlerini Linkten Al
    nameEn = urlParams.get('n1'); // n1 parametresi: 1. Buton ismi
    nameTr = urlParams.get('n2'); // n2 parametresi: 2. Buton ismi

    const generatorScreen = document.getElementById('generator-screen');
    const playerWrapper = document.getElementById('player-wrapper');
    const switcher = document.getElementById('lang-switcher');

    if (linkEn) {
        generatorScreen.style.display = 'none';
        playerWrapper.style.display = 'block';

        // Buton isimlerini güncelle (Varsayılan değerleri koru)
        if(nameEn) document.getElementById('txt-en').innerText = nameEn;
        if(nameTr) document.getElementById('txt-tr').innerText = nameTr;

        if(linkTr && linkTr.length > 5) {
            switcher.style.display = 'flex';
        }
        initPlayer(linkEn, linkSub);
    }
    else {
        generatorScreen.style.display = 'flex';
    }
};

function initPlayer(videoSource, subSource) {
    let tracks = [];
    if(subSource && subSource.length > 5) {
        tracks.push({
            kind: 'captions', label: 'Türkçe', srclang: 'tr', src: subSource, default: true
        });
    }

    player = new Plyr('#player', {
        controls: ['play-large', 'play', 'progress', 'current-time', 'mute', 'volume', 'captions', 'settings', 'pip', 'fullscreen'],
        autoplay: true,
        fullscreen: { 
            enabled: true, 
            fallback: true, 
            iosNative: true, 
            container: null 
        },
        playsinline: true,
        captions: { active: true, update: true, language: 'tr' }
    });

    player.source = {
        type: 'video',
        sources: [{ src: videoSource, type: 'video/mp4' }],
        tracks: tracks
    };
}

function changeLang(lang) {
    if(lang === currentLang) return;

    var currentTime = player.currentTime;
    var isPaused = player.paused;

    document.getElementById('btn-en').classList.remove('active');
    document.getElementById('btn-tr').classList.remove('active');
    document.getElementById('btn-' + lang).classList.add('active');

    let newSrc = (lang === 'tr') ? linkTr : linkEn;
    let currentTracks = (linkSub) ? [{
        kind: 'captions', label: 'Türkçe', srclang: 'tr', src: linkSub, default: (lang === 'en')
    }] : [];

    player.source = {
        type: 'video',
        sources: [{ src: newSrc, type: 'video/mp4' }],
        tracks: currentTracks
    };

    player.once('ready', event => {
        player.currentTime = currentTime;
        if(!isPaused) player.play();
    });

    currentLang = lang;
}

function createLink() {
    var v = document.getElementById('vidOriginal').value.trim();
    var d = document.getElementById('vidDubbed').value.trim();
    var s = document.getElementById('vidSub').value.trim();

    // Yeni inputlardan değerleri al
    var n1 = document.getElementById('btnName1').value.trim();
    var n2 = document.getElementById('btnName2').value.trim();

    if(!v) { alert("Lütfen video linki giriniz."); return; }

    var baseUrl = window.location.protocol + "//" + window.location.host + window.location.pathname;
    var finalUrl = baseUrl + "?v=" + encodeURIComponent(v);

    if(d) finalUrl += "&d=" + encodeURIComponent(d);
    if(s) finalUrl += "&s=" + encodeURIComponent(s);

    // İsimler girilmişse linke ekle
    if(n1) finalUrl += "&n1=" + encodeURIComponent(n1);
    if(n2) finalUrl += "&n2=" + encodeURIComponent(n2);

    var resultBox = document.getElementById('resultArea');
    var linkTag = document.getElementById('generatedLink');

    resultBox.style.display = 'block';
    linkTag.innerText = finalUrl;
    linkTag.href = finalUrl;
}
//
